import{_ as d,o as e,c as a,ae as o}from"./chunks/framework.DTwQaIIa.js";const b=JSON.parse('{"title":"命令与权限","description":"","frontmatter":{},"headers":[],"relativePath":"modules/attribute/commands.md","filePath":"modules/attribute/commands.md"}'),c={name:"modules/attribute/commands.md"};function r(s,t,i,n,l,p){return e(),a("div",null,[...t[0]||(t[0]=[o(`<h1 id="命令与权限" tabindex="-1">命令与权限 <a class="header-anchor" href="#命令与权限" aria-label="Permalink to &quot;命令与权限&quot;">​</a></h1><h2 id="命令" tabindex="-1">命令 <a class="header-anchor" href="#命令" aria-label="Permalink to &quot;命令&quot;">​</a></h2><p>根命令：<code>/emakiattribute</code>（别名 <code>/eattribute</code>、<code>/ea</code>）</p><table tabindex="0"><thead><tr><th>子命令</th><th>用法</th><th>权限</th><th>说明</th></tr></thead><tbody><tr><td><code>help</code></td><td><code>/ea help</code></td><td><code>emakiattribute.use</code></td><td>显示帮助信息</td></tr><tr><td><code>reload</code></td><td><code>/ea reload</code></td><td><code>emakiattribute.reload</code></td><td>异步重载所有配置文件，完成后输出加载统计</td></tr><tr><td><code>resync</code></td><td><code>/ea resync [玩家|all]</code></td><td><code>emakiattribute.resync</code></td><td>重新同步属性快照。不带参数同步自己，<code>all</code> 同步所有在线玩家</td></tr><tr><td><code>preview</code></td><td><code>/ea preview [玩家] [槽位]</code></td><td><code>emakiattribute.debug</code></td><td>查看指定玩家指定槽位物品的属性快照</td></tr><tr><td><code>dump</code></td><td><code>/ea dump [玩家]</code></td><td><code>emakiattribute.debug</code></td><td>导出玩家的完整战斗属性快照和资源状态</td></tr><tr><td><code>debug</code></td><td><code>/ea debug [玩家] [toggle|on|off]</code></td><td><code>emakiattribute.debug</code></td><td>切换战斗调试模式，开启后控制台会输出详细的伤害计算日志</td></tr><tr><td><code>lint</code></td><td><code>/ea lint</code></td><td><code>emakiattribute.reload</code></td><td>检查所有配置文件的合法性，报告潜在问题</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">reload 是异步的</p><p><code>reload</code> 不会阻塞主线程，重载过程中会逐步输出进度。完成后会告诉你加载了多少属性、多少伤害类型、多少档案。如果某个文件有问题，也会在这里报错。</p></div><h2 id="权限节点" tabindex="-1">权限节点 <a class="header-anchor" href="#权限节点" aria-label="Permalink to &quot;权限节点&quot;">​</a></h2><table tabindex="0"><thead><tr><th>权限</th><th>默认</th><th>说明</th></tr></thead><tbody><tr><td><code>emakiattribute.use</code></td><td><code>true</code></td><td>基础命令（help），所有玩家默认拥有</td></tr><tr><td><code>emakiattribute.reload</code></td><td><code>op</code></td><td>重载配置和 lint 检查</td></tr><tr><td><code>emakiattribute.resync</code></td><td><code>op</code></td><td>重新同步属性</td></tr><tr><td><code>emakiattribute.debug</code></td><td><code>op</code></td><td>preview、dump、debug 命令</td></tr><tr><td><code>emakiattribute.admin</code></td><td><code>op</code></td><td>超级权限，包含以上所有</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">权限继承</p><p><code>emakiattribute.admin</code> 包含所有其他权限，给了这个就不需要再单独授予 <code>reload</code>、<code>resync</code> 等权限了。</p></div><h2 id="preview-槽位名称" tabindex="-1">Preview 槽位名称 <a class="header-anchor" href="#preview-槽位名称" aria-label="Permalink to &quot;Preview 槽位名称&quot;">​</a></h2><p><code>preview</code> 命令用来查看某个装备槽位上物品的属性快照，排查&quot;为什么这件装备的属性没生效&quot;之类的问题时很有用。</p><table tabindex="0"><thead><tr><th>槽位</th><th>别名</th><th>说明</th></tr></thead><tbody><tr><td><code>main_hand</code></td><td><code>mainhand</code>、<code>hand</code></td><td>主手</td></tr><tr><td><code>off_hand</code></td><td><code>offhand</code></td><td>副手</td></tr><tr><td><code>helmet</code></td><td>—</td><td>头盔</td></tr><tr><td><code>chestplate</code></td><td><code>chest</code></td><td>胸甲</td></tr><tr><td><code>leggings</code></td><td><code>legs</code></td><td>护腿</td></tr><tr><td><code>boots</code></td><td>—</td><td>靴子</td></tr></tbody></table><p>用法示例：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/ea preview                    # 预览自己主手物品（默认槽位）</span></span>
<span class="line"><span>/ea preview main_hand          # 同上</span></span>
<span class="line"><span>/ea preview Steve helmet       # 预览 Steve 的头盔</span></span>
<span class="line"><span>/ea preview chestplate         # 预览自己的胸甲</span></span></code></pre></div><h2 id="debug-调试模式" tabindex="-1">Debug 调试模式 <a class="header-anchor" href="#debug-调试模式" aria-label="Permalink to &quot;Debug 调试模式&quot;">​</a></h2><p>调试模式开启后，每次伤害计算都会在控制台输出完整的计算日志，包括攻击者/目标的属性快照、各阶段的计算值、暴击判定结果等。排查伤害数值不对的问题时非常有用。</p><table tabindex="0"><thead><tr><th>操作</th><th>别名</th><th>说明</th></tr></thead><tbody><tr><td><code>toggle</code></td><td>—</td><td>切换调试状态（默认操作）</td></tr><tr><td><code>on</code></td><td><code>enable</code>、<code>true</code></td><td>开启调试</td></tr><tr><td><code>off</code></td><td><code>disable</code>、<code>false</code></td><td>关闭调试</td></tr></tbody></table><p>用法示例：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/ea debug                      # 切换自己的调试状态</span></span>
<span class="line"><span>/ea debug on                   # 开启自己的调试</span></span>
<span class="line"><span>/ea debug Steve off            # 关闭 Steve 的调试</span></span>
<span class="line"><span>/ea debug Steve                # 切换 Steve 的调试状态</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">注意性能影响</p><p>调试模式会在每次伤害计算时输出大量日志。如果服务器上有高频战斗（比如刷怪塔），控制台可能会被日志刷屏。建议只在排查问题时临时开启，用完记得关掉。</p></div><h2 id="lint-检查项" tabindex="-1">Lint 检查项 <a class="header-anchor" href="#lint-检查项" aria-label="Permalink to &quot;Lint 检查项&quot;">​</a></h2><p><code>lint</code> 命令会扫描所有配置文件，检查常见的配置错误。建议在修改配置后跑一次，比 reload 后发现问题再排查要高效得多。</p><table tabindex="0"><thead><tr><th>检查区域</th><th>检查内容</th></tr></thead><tbody><tr><td>主配置</td><td><code>default_damage_type</code> 是否指向有效的伤害类型；<code>allowed_damage_causes</code> 中的伤害类型引用是否存在</td></tr><tr><td>属性定义</td><td>属性文件的格式和字段合法性</td></tr><tr><td>伤害类型</td><td>伤害类型文件的格式和阶段定义合法性</td></tr><tr><td>默认属性配置</td><td>档案文件的格式合法性</td></tr><tr><td>Lore 格式</td><td>Lore 格式文件的格式合法性</td></tr><tr><td>属性预设</td><td>预设文件的格式合法性</td></tr><tr><td>属性读取条件</td><td>条件文件的格式和引用合法性</td></tr></tbody></table>`,22)])])}const u=d(c,[["render",r]]);export{b as __pageData,u as default};
